23	  }
24	}
25	
26	const results = [];
27	const policies = [];
28	
29	for (const step of scenario.steps) {
30	  if (step.op === "quote") {
31	    assertKnownItemTypes(step.items);
32	    const { premium } = quote({
33	      items: step.items,
34	      yearsWithMHPCO,
35	      firstInsurance: true,
36	      followUp: policies.length > 0,
37	    });
38	    policies.push(step);
